@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-950: #000000;
  --color-deep-blue: #0f1015;
  --color-indigo: #7d2ae8;
  --color-deep-blue-2: #1c2130;
  --color-indigo-2: #a370fc;
  --color-teal: #00c4cc;
  --color-indigo-3: #8b3dff;
  --color-blue: #5a32fa;
  --color-cyan: #1a73e8;
  --color-teal-2: #13a3b5;
  --color-red: #fd4958;
  --color-indigo-4: #992bff;
  --color-pale-indigo: #f1ebff;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #000000;
  --color-accent: #0f1015;
  --color-accent-2: #7d2ae8;
  --color-accent-3: #1c2130;

  --font-sans: "Noto Sans", ui-sans-serif, system-ui, sans-serif;

  --text-xs: 0.6875rem;
  --text-sm: 0.75rem;
  --text-base: 0.875rem;
  --text-lg: 1rem;
  --text-xl: 1.09375rem;
  --text-2xl: 1.125rem;
  --text-3xl: 1.5rem;
  --text-4xl: 2.25rem;
  --text-5xl: 3rem;
  --text-6xl: 4.125rem;
  --text-7xl: 5.5rem;
  --text-8xl: 8rem;

  --font-weight-thin: 100;
  --font-weight-light: 300;
  --font-weight-normal: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* line-heights, sorted tight -> loose */
  --leading-none: 1;
  --leading-tight: 1.04;
  --leading-snug: 1.06;
  --leading-normal: 1.1;
  --leading-relaxed: 1.2;
  --leading-loose: 1.25;
  --leading-looser: 1.4;
  --leading-loosest: 1.6;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: -1.5px;
  --tracking-tighter: -.64px;
  --tracking-tight: -.28px;
  --tracking-normal: -.01em;
  --tracking-wide: .25px;
  --tracking-wider: .3px;

  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 10px;
  --radius-xl: 12px;
  --radius-2xl: 16px;
  --radius-3xl: 20px;
  --radius-4xl: 24px;
  --radius-full: 9999px;

  /* shadows, sorted by blur */
  --shadow-sm: 0 -16px 20px rgba(14,19,24,.04);
  --shadow-md: shadowSurface;

  --breakpoint-sm: 22rem;
  --breakpoint-md: 25.625rem;
  --breakpoint-lg: 27rem;
  --breakpoint-xl: 37.4375rem;
  --breakpoint-2xl: 37.5rem;
  --breakpoint-3xl: 55rem;
  --breakpoint-4xl: 56.1875rem;
  --breakpoint-5xl: 56.25rem;

  /* most-used spacing values on the source site (px): 1, 2, 4, 6, 8, 10, 12, 16, 24, 32, 48, 64 */
}

